return items.map(item => ({
  json: {
    coldroom_name: (item.json.coldroom_name || "Unknown")
      .toString()
      .replace(/\s+/g, "")
      .toLowerCase(),
    temperature: Number(item.json.temperature),
    humidity: Number(item.json.humidity),
    sensor_timestamp: item.json.sensor_timestamp
  }
}));

return items.map(item => {

  let intense = 0;
  if (item.json.anomaly == 1) intense += 2;
  if (item.json.isNight && item.json.anomaly == 1) intense += 1;
  if (item.json.isWeekend && item.json.anomaly == 1) intense += 1;
  if (!item.json.isPeak && item.json.temperature > 35) intense += 2;

  if (item.json.reconstruction_error > item.json.threshold * 0.8)
    intense += 2;

  let level = "Normal";

  if (intense >= 4) level = "Critical";
  else if (intense >= 2) level = "Warning";


  return {
    json: {
      ...item.json,
      intense,
      level,

    }
  };
});

const input = $json.Inputfield || $json.text || $json.output || "";

const message = input
  .toString()
  .toLowerCase()
  .replace(/[^\w\s-]/g, '')
  .trim();

let roomMatch = message.match(/cold\s*-?\s*room\s*(\d+)/);

return {
  requested_room: roomMatch ? `coldroom${roomMatch[1]}` : null,
  original_input: input // Good for debugging!
};

