const staticData = $getWorkflowStaticData('global');
const requestedRoom = staticData.requested_room;
if (!requestedRoom) return items;

staticData.requested_room = null;

return items.filter(item =>
  item.json.coldroom_name === requestedRoom
);

const now = new Date().toLocaleString();

const alertsHtml = items.map(item => {
  let output = item.json.output || '';

  // 1. HEADER DATA EXTRACTION
  const roomMatch = output.match(/\*\*?(coldroom\d+)\*\*?/i);
  const roomName = roomMatch ? roomMatch[1].toUpperCase() : 'COLDROOM';

  let severity = 'Normal'; 
  if (output.toLowerCase().includes('critical')) severity = 'Critical';
  else if (output.toLowerCase().includes('warning') || output.toLowerCase().includes('preventive')) severity = 'Warning';

  // 2. TABLE EXTRACTION & TEXT CLEANING
  const lines = output.split('\n');
  let tableLines = [];
  let textLines = [];

  // Har line ko check karein: Agar pipe '|' hai toh table ka hissa hai
  lines.forEach(line => {
    if (line.trim().startsWith('|') || (line.trim().includes('|') && line.trim().length > 5)) {
      tableLines.push(line);
    } else {
      // Room name aur Severity ko body text se nikalne ke liye
      if (!line.toLowerCase().includes('coldroom') && !line.toLowerCase().includes('severity level')) {
        textLines.push(line);
      }
    }
  });

  let tableHtml = '';
  if (tableLines.length > 0) {
    // Markdown separator (---) ko filter out karein
    const filteredRows = tableLines.filter(l => !l.includes('---') && !l.includes(':---'));

    if (filteredRows.length > 0) {
      const headerLine = filteredRows.shift();
      const headers = headerLine.split('|').filter(c => c.trim()).map(c => 
        `<th style="padding:12px; background:#F1F5F9; border-bottom:2px solid #CBD5E1; text-align:left; font-size:11px; color:#475569; text-transform:uppercase;">${c.trim()}</th>`
      ).join('');

      const rows = filteredRows.map((line, index) => {
        const cells = line.split('|').filter(c => c.trim()).map(c => 
          `<td style="padding:10px; border-bottom:1px solid #E2E8F0; font-family:monospace; font-size:12px; color:#64748B;">${c.trim()}</td>`
        ).join('');
        const rowBg = index % 2 === 0 ? '#ffffff' : '#F8FAFC';
        return `<tr style="background:${rowBg};">${cells}</tr>`;
      }).join('');

      tableHtml = `
        <div style="margin-top:20px; border:1px solid #E2E8F0; border-radius:10px; overflow:hidden;">
          <table style="width:100%; border-collapse:collapse; background:white;">
            <thead><tr>${headers}</tr></thead>
            <tbody>${rows}</tbody>
          </table>
        </div>`;
    }
  }

  // 3. CLEAN BODY TEXT
  const cleanBody = textLines.join('<br>').replace(/(<br>){2,}/g, '<br><br>').trim();

  // 4. THEME CONFIG
  const styles = {
    Critical: { border: '#EF4444', bg: '#FEE2E2', text: '#991B1B', icon: '🚨' },
    Warning:  { border: '#F59E0B', bg: '#FEF3C7', text: '#92400E', icon: '⚠️' },
    Normal:   { border: '#10B981', bg: '#D1FAE5', text: '#065F46', icon: '✅' }
  };
  const theme = styles[severity] || styles.Normal;

  return `
    <div style="margin-bottom:30px; background:#ffffff; border-radius:12px; border-left:8px solid ${theme.border}; box-shadow:0 4px 6px rgba(0,0,0,0.05); overflow:hidden; border:1px solid #E2E8F0; border-left:8px solid ${theme.border};">
        <div style="padding:12px 20px; background:#F8FAFC; border-bottom:1px solid #E2E8F0;">
            <table width="100%" border="0" cellpadding="0" cellspacing="0">
              <tr>
                <td style="font-weight:bold; color:#1E293B; font-size:16px;">${theme.icon} ${roomName}</td>
                <td align="right">
                  <span style="padding:4px 12px; border-radius:15px; font-size:10px; font-weight:bold; background:${theme.bg}; color:${theme.text}; text-transform:uppercase;">
                    ${severity}
                  </span>
                </td>
              </tr>
            </table>
        </div>
        <div style="padding:20px; font-size:14px; color:#334155; line-height:1.6;">
            ${cleanBody}
            ${tableHtml}
        </div>
    </div>
  `;
}).join('');

const fullHtml = `
<!DOCTYPE html>
<html>
<body style="background:#F1F5F9; padding:20px; font-family:Helvetica, Arial, sans-serif;">
  <div style="max-width:650px; margin:0 auto;">
    <div style="background:#1E40AF; color:#ffffff; padding:30px; border-radius:15px; text-align:center; margin-bottom:25px;">
      <h2 style="margin:0; font-size:24px;">Coldroom Analysis Report</h2>
      <div style="font-size:12px; opacity:0.8; margin-top:8px;">${now}</div>
    </div>
    ${alertsHtml}
  </div>
</body>
</html>
`;

return [{ json: { html: fullHtml } }];
